export function dijkstraShortestPath(nodeCount: number, edges: readonly (readonly [number, number, number])[], start: number, end: number): number | null {
    const adj: Array<Array<[number, number]>> = new Array(nodeCount);
    for (let i = 0; i < nodeCount; i++) adj[i] = [];
    for (const [u, v, w] of edges) {
        adj[u].push([v, w]);
    }

    const dist = new Array(nodeCount).fill(Infinity);
    dist[start] = 0;

    const pq: [number, number][] = [[0, start]];

    while (pq.length > 0) {
        const [d, u] = pq[0];
        if (pq.length > 1) {
            pq[0] = pq.pop()!;
            let i = 0;
            const n = pq.length;
            while (true) {
                let smallest = i;
                const l = 2 * i + 1;
                const r = 2 * i + 2;
                if (l < n && pq[l][0] < pq[smallest][0]) smallest = l;
                if (r < n && pq[r][0] < pq[smallest][0]) smallest = r;
                if (smallest === i) break;
                const tmp = pq[i]; pq[i] = pq[smallest]; pq[smallest] = tmp;
                i = smallest;
            }
        } else {
            pq.pop();
        }

        if (d > dist[u]) continue;
        if (u === end) return d;

        for (const [v, w] of adj[u]) {
            const newDist = d + w;
            if (newDist < dist[v]) {
                dist[v] = newDist;
                pq.push([newDist, v]);
                let i = pq.length - 1;
                while (i > 0) {
                    const p = (i - 1) >> 1;
                    if (pq[p][0] <= pq[i][0]) break;
                    const tmp = pq[i]; pq[i] = pq[p]; pq[p] = tmp;
                    i = p;
                }
            }
        }
    }

    return dist[end] === Infinity ? null : dist[end];
}

