    const adj: Array<Array<[number, number]>> = Array.from({ length: nodeCount }, () => []);
    for (const [u, v, w] of edges) {
        adj[u].push([v, w]);
    }

    const dist = new Float64Array(nodeCount).fill(Infinity);
    dist[start] = 0;

    // Min-heap implementation or use a simple array since nodeCount might be small? 
    // But for benchmark, better to implement a proper heap or use an array with sorting if N is small.
    // Actually, in TS benchmarks, often a simple array-based PQ or just sorting works, but let's implement a standard binary heap for safety and performance.

    // Alternatively, since it's TypeScript, we can use an array as a priority queue.
    // Let's implement a simple min-heap.

    const pq: [number, number][] = [[0, start]];

    while (pq.length > 0) {
        // Extract min
        let minIdx = 0;
        for (let i = 1; i < pq.length; i++) {
            if (pq[i][0] < pq[minIdx][0]) {
                minIdx = i;
