export function evaluateBooleanExpression(expression: string): boolean {
    let pos = 0;
    const len = expression.length;

    function skipWhitespace() {
        while (pos < len && ' \t\n\r'.indexOf(expression[pos]) !== -1) {
            pos++;
        }
    }

    function parseLiteral(): boolean {
        skipWhitespace();
        if (expression.slice(pos, pos + 4) === 'true') {
            pos += 4;
            return true;
        }
        if (expression.slice(pos, pos + 5) === 'false') {
            pos += 5;
            return false;
        }
        throw new Error('Invalid literal');
    }

    function parseFactor(): boolean {
        skipWhitespace();
        if (pos >= len) throw new Error('Unexpected end');

        const char = expression[pos];
        if (char === '!') {
            pos++;
            return !parseFactor();
        }
        if (char === '(') {
            pos++;
            const result = parseExpression();
            skipWhitespace();
            if (expression[pos] !== ')') throw new Error('Expected )');
            pos++;
            return result;
        }
        return parseLiteral();
    }

    function parseTerm(): boolean {
        let result = parseFactor();
        while (true) {
            skipWhitespace();
            if (expression.slice(pos, pos + 2) === '&&') {
                pos += 2;
                const right = parseFactor();
                result = result && right;
            } else {
                break;
            }
        }
        return result;
    }

    function parseExpression(): boolean {
        let result = parseTerm();
        while (true) {
            skipWhitespace();
            if (expression.slice(pos, pos + 2) === '||') {
                pos += 2;
                const right = parseFactor();
                result = result || right;
            } else {
                break;
            }
        }
        return result;
    }

    skipWhitespace();
    if (pos >= len) return false;
    const result = parseExpression();
    skipWhitespace();
    if (pos < len) throw new Error('Unexpected characters');
    return result;
}

