    let h1 = seed | 0;
    const c1 = 0xcc9e2d51;
    const c2 = 0x1b873593;
    const len = str.length;
    let i = 0;

    for (; i <= len - 4; i += 4) {
        let k = (str.charCodeAt(i) & 0xff) |
                ((str.charCodeAt(i + 1) & 0xff) << 8) |
                ((str.charCodeAt(i + 2) & 0xff) << 16) |
