    const getHeight = (n: Node | null): number => n?.height ?? 0;
    const getBalance = (n: Node | null): number => (n ? getHeight(n.left) - getHeight(n.right) : 0);

    const updateHeight = (n: Node): void => {
        n.height = 1 + Math.max(getHeight(n.left), getHeight(n.right));
    };

    const rightRotate = (y: Node): Node => {
        const x = y.left!;
        const T2 = x.right;
        x.right = y;
        y.left = T2;
        updateHeight(y);
        updateHeight(x);
        return x;
    };

    const leftRotate = (x: Node): Node => {
        const y = x.right!;
        const T2 = y.left;
        y.left = x;
        x.right = T2;
        updateHeight(x);
        updateHeight(y);
        return y;
    };

