interface Node {
  keys: number[];
  children?: Node[];
}

export function createBStarTree(t: number) {
  const root: Node = { keys: [] };
  const minKeys = 2 * t - 1;
  const maxKeys = 3 * t - 1;

  function isLeaf(node: Node): boolean {
    return !node.children || node.children.length === 0;
  }

  function splitNode(node: Node): [Node, number, Node] {
    const mid = Math.floor(node.keys.length / 2);
    const pivot = node.keys[mid];
    const left: Node = { keys: node.keys.slice(0, mid) };
    const right: Node = { keys: node.keys.slice(mid + 1) };
    if (node.children) {
      left.children = node.children.slice(0, mid + 1);
      right.children = node.children.slice(mid + 1);
    }
    return [left, pivot, right];
  }

  function tryRedistribute(node: Node, i: number): boolean {
    if (i > 0 && node.children![i - 1].keys.length > minKeys) {
      const left = node.children![i - 1];
      node.keys[i - 1] = left.keys.pop()!;
      if (!isLeaf(left)) {
        left.children!.push(node.children![i].children![0]);
        node.children![i].children!.shift();
      }
      return true;
    }
    if (i < node.keys.length && node.children![i + 1].keys.length > minKeys) {
      const right = node.children![i + 1];
      node.keys[i] = right.keys.shift()!;
      if (!isLeaf(right)) {
        right.children!.unshift(node.children![i].children![node.children![i].children!.length - 1]);
        node.children![i].children!.pop();
      }
      return true;
    }
    return false;
  }

  function insertNonFull(node: Node, key: number): void {
    let i = node.keys.length - 1;
    if (isLeaf(node)) {
      while (i >= 0 && key < node.keys[i]) i--;
      node.keys.splice(i + 1, 0, key);
      return;
    }

    while (i >= 0 && key < node.keys[i]) i--;
    i++;

    if (node.children![i].keys.length === maxKeys) {
      if (!tryRedistribute(node, i)) {
        const [left, pivot, right] = splitNode(node.children![i]);
        if (i < node.keys.length && key > node.keys[i]) i++;
        node.keys.splice(i, 0, pivot);
        node.children![i] = left;
        node.children!.splice(i + 1, 0, right);
      }
    }

    insertNonFull(node.children![i], key);
  }

  function searchNode(node: Node, key: number): boolean {
    let i = 0;
    while (i < node.keys.length && key > node.keys[i]) i++;
    if (i < node.keys.length && key === node.keys[i]) return true;
    if (isLeaf(node)) return false;
    return searchNode(node.children![i], key);
  }

  function rotateLeft(node: Node, i: number): void {
    const left = node.children![i - 1];
    node.keys[i - 1] = left.keys.pop()!;
    if (!isLeaf(left)) {
      left.children!.push(node.children![i].children![0]);
      node.children![i].children!.shift();
    }
  }

  function rotateRight(node: Node, i: number): void {
    const right = node.children![i + 1];
    node.keys[i] = right.keys.shift()!;
    if (!isLeaf(right)) {
      right.children!.unshift(node.children![i].children![node.children![i].children!.length - 1]);
      node.children![i].children!.pop();
    }
  }

  function mergeChildren(node: Node, i: number): void {
    const left = node.children![i];
    const right = node.children![i + 1];
    left.keys.push(node.keys[i], ...right.keys);
    if (!isLeaf(left)) {
      left.children!.push(...right.children!);
    }
    node.keys.splice(i, 1);
    node.children!.splice(i + 1, 1);
  }

  function deleteNode(node: Node, key: number): void {
    let i = 0;
    while (i < node.keys.length && key > node.keys[i]) i++;

    if (i < node.keys.length && key === node.keys[i]) {
      if (isLeaf(node)) {
        node.keys.splice(i, 1);
        return;
      } else {
        const left = node.children![i];
        const right = node.children![i + 1];

        if (left.keys.length >= minKeys) {
          let pred = left;
          while (!isLeaf(pred)) pred = pred.children![pred.children!.length - 1];
          const predKey = pred.keys.pop()!;
          node.keys[i] = predKey;
          deleteNode(left, predKey);
        } else if (right && right.keys.length >= minKeys) {
          let succ = right;
          while (!isLeaf(succ)) succ = succ.children![0];
          const succKey = succ.keys.shift()!;
          node.keys[i] = succKey;
          deleteNode(right, succKey);
        } else {
          mergeChildren(node, i);
          deleteNode(node.children![i], key);
        }
      }
    } else {
      if (isLeaf(node)) return;

      let child = node.children![i];
      if (child.keys.length < minKeys) {
        if (i > 0 && node.children![i - 1].keys.length >= minKeys) {
          rotateLeft(node, i);
        } else if (i < node.keys.length && node.children![i + 1].keys.length >= minKeys) {
          rotateRight(node, i);
        } else {
          if (i > 0) mergeChildren(node, i - 1);
          else mergeChildren(node, i);
          child = node.children![i];
        }
      }
      deleteNode(child, key);
    }

    if (isLeaf(root) && root.keys.length === 0) {
      root.keys = [];
    } else if (!isLeaf(root) && root.keys.length === 0) {
      const newRoot = root.children![0];
      root.keys = newRoot.keys;
      root.children = newRoot.children;
    }
  }

  function insert(key: number): void {
    if (root.keys.length === maxKeys) {
      const [left, pivot, right] = splitNode(root);
      root.keys = [pivot];
      root.children = [left, right];
    }
    insertNonFull(root, key);
  }

  function search(key: number): boolean {
    return searchNode(root, key);
  }

  function deleteKey(key: number): void {
    deleteNode(root, key);
  }

  function keys(): number[] {
    const result: number[] = [];
    function inorder(node: Node) {
      if (!node) return;
      if (isLeaf(node)) {
        result.push(...node.keys);
        return;
      }
      for (let i = 0; i < node.children!.length; i++) {
        inorder(node.children![i]);
        if (i < node.keys.length) result.push(node.keys[i]);
      }
    }
    inorder(root);
    return result;
  }

  return { insert, search, delete: deleteKey, keys };
}

