export function createBTree(t: number): {insert: (key: number) => void; search: (key: number) => boolean; delete: (key: number) => void; keys: () => number[]} {
  const MAX_KEYS = 2 * t - 1;
  let root: Node | null = null;

  function splitChild(parent: Node, i: number) {
    const child = parent.children[i];
    const mid = Math.floor(child.keys.length / 2);
    const midKey = child.keys[mid];

    const left: Node = { keys: [], children: [] };
    const right: Node = { keys: [], children: [] };

    left.keys = child.keys.slice(0, mid);
    right.keys = child.keys.slice(mid + 1);

    if (child.children.length > 0) {
      left.children = child.children.slice(0, mid + 1);
      right.children = child.children.slice(mid + 1);
    }

    parent.keys.splice(i, 0, midKey);
    parent.children.splice(i, 1, left, right);
  }

  function insertNonFull(node: Node, key: number) {
    let i = node.keys.length - 1;
    if (node.children.length === 0) {
      while (i >= 0 && key < node.keys[i]) i--;
      if (i >= 0 && node.keys[i] === key) return;
      node.keys.splice(i + 1, 0, key);
      return;
    }

    while (i >= 0 && key < node.keys[i]) i--;
    i++;

    if (node.children[i].keys.length === MAX_KEYS) {
      splitChild(node, i);
      if (key > node.keys[i]) i++;
    }

    insertNonFull(node.children[i], key);
  }

  function insert(key: number): void {
    if (!root) {
      root = { keys: [key], children: [] };
      return;
    }
    if (root.keys.length === MAX_KEYS) {
      const newRoot: Node = { keys: [], children: [root] };
      splitChild(newRoot, 0);
      let i = 0;
      if (newRoot.keys[0] < key) i++;
      insertNonFull(newRoot.children[i], key);
      root = newRoot;
    } else {
      insertNonFull(root, key);
    }
  }

  function search(key: number): boolean {
    let node = root;
    while (node) {
      let i = node.keys.length - 1;
      while (i >= 0 && key < node.keys[i]) i--;
      if (i >= 0 && node.keys[i] === key) return true;
      if (node.children.length === 0) break;
      node = node.children[i + 1];
    }
    return false;
  }

  function borrowFromLeft(node: Node, i: number) {
    const child = node.children[i];
    const sibling = node.children[i - 1];
    child.keys.unshift(node.keys[i - 1]);
    node.keys[i - 1] = sibling.keys.pop()!;
    if (sibling.children.length > 0) {
