    if (!root) return;
    if (!search(key)) return;
    deleteKey(root, key);
    if (root.keys.length === 0 && root.children.length > 0) {
      root = root.children[0];
    }
  }

  function keys(): number[] {
    const result: number[] = [];
    function traverse(node: Node | null) {
      if (!node) return;
      for (let i = 0; i < node.keys.length; i++) {
        if (node.children.length > 0) traverse(node.children[i]);
        result.push(node.keys[i]);
      }
      if (node.children.length > 0) traverse(node.children[node.children.length - 1]);
    }
    traverse(root);
    return result;
  }

  return { insert, search, delete: delete, keys };
}

