    const child = parent.children[i];
    const mid = Math.floor(child.keys.length / 2);
    const midKey = child.keys[mid];

    const left: Node = { keys: [], children: [] };
    const right: Node = { keys: [], children: [] };

    left.keys = child.keys.slice(0, mid);
    right.keys = child.keys.slice(mid + 1);

    if (child.children.length > 0) {
      left.children = child.children.slice(0, mid + 1);
      right.children = child.children.slice(mid + 1);
    }

    parent.keys.splice(i, 0, midKey);
    parent.children.splice(i, 1, left, right);
  }

