export function kLargestElementsInStream(stream: number[], k: number): number[][] {
    const result: number[][] = [];
    if (k <= 0) return stream.map(() => []);

    const heap: number[] = [];

    const push = (val: number) => {
        heap.push(val);
        let i = heap.length - 1;
        while (i > 0) {
            const parent = (i - 1) >> 1;
            if (heap[parent] <= heap[i]) break;
            [heap[parent], heap[i]] = [heap[i], heap[parent]];
            i = parent;
        }
    };

    const pop = () => {
        const top = heap[0];
        const last = heap.pop()!;
        if (heap.length > 0) {
            heap[0] = last;
            let i = 0;
            while (true) {
                let smallest = i;
                const left = 2 * i + 1;
                const right = 2 * i + 2;
                if (left < heap.length && heap[left] < heap[smallest]) smallest = left;
                if (right < heap.length && heap[right] < heap[smallest]) smallest = right;
                if (smallest === i) break;
                [heap[i], heap[smallest]] = [heap[smallest], heap[i]];
                i = smallest;
            }
        }
        return top;
    };

    for (const num of stream) {
        if (heap.length < k) {
            push(num);
        } else if (num > heap[0]) {
            pop();
            push(num);
        }

        result.push([...heap].sort((a, b) => b - a));
    }

    return result;
}

