export const html06DialogModal = (): string => {
	return `<button id="open-btn">Open Modal</button>
<dialog id="my-dialog" aria-labelledby="dialog-title" aria-describedby="dialog-description">
  <h2 id="dialog-title">Confirm Action</h2>
  <p id="dialog-description">Are you sure you want to proceed?</p>
  <button id="close-btn" aria-label="Close dialog">Close</button>
</dialog>
<script>
  const dialog = document.getElementById('my-dialog');
  const closeBtn = document.getElementById('close-btn');

  document.getElementById('open-btn').addEventListener('click', () => dialog.showModal());
  closeBtn.addEventListener('click', () => dialog.close());

  dialog.addEventListener('keydown', (e) => {
    if (e.key === 'Escape') {
      dialog.close();
      return;
    }
    if (e.key === 'Tab') {
      const focusable = Array.from(dialog.querySelectorAll('button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'));
      const first = focusable[0];
      const last = focusable[focusable.length - 1];

      if (e.shiftKey && document.activeElement === first) {
        e.preventDefault();
        last?.focus();
      } else if (!e.shiftKey && document.activeElement === last) {
        e.preventDefault();
        first?.focus();
      }
    }
  });

  dialog.addEventListener('click', (e) => {
    if (e.target === dialog) {
      dialog.close();
    }
  });
</script>`;
};

